/*---------- 引脚定义 ----------*/
#define LED_GREEN       (1U << 12)
#define LED_ORANGE      (1U << 13)
#define LED_RED         (1U << 14)
#define LED_BLUE        (1U << 15)
#define LED_ALL         (LED_GREEN | LED_ORANGE | LED_RED | LED_BLUE)

/* BUZZER (PF8) — ALIENTEK 探索者 STM32F407
 * 例程配置: GPIO_PuPd_DOWN + 默认 GPIO_ResetBits (拉低 = 静音),
 * 也就是说 PF8=1 时蜂鸣器响 (active-high). */
#define BUZZER_PIN      (1U << 8)    /* PF8 (BEEP) */
#define KEY0_PIN        (1U << 4)    /* PE4 (KEY0) */
#define KEY1_PIN        (1U << 3)    /* PE3 (KEY1) */
#define KEY2_PIN        (1U << 2)    /* PE2 (KEY2) */

/*---------- 全局状态 ----------*/
static float target_voltage = 1.5f;
static float measured_voltage = 0.0f;
static float chip_temperature = 0.0f;
static float vrefint_raw = 0.0f;     /* one-shot VREFINT 12-bit probe */
static uint16_t threshold_high = 3000;
static uint16_t threshold_low  = 1000;
static uint8_t alarm_active = 0;
static uint8_t blink_state = 0;

/*---------- PID 控制器 (增量式) ----------*
 * 控制律: target_voltage 由用户设定, measured_voltage 由 ADC 采样得到,
 *         PID 控制器计算出 dac_output, 写到 DAC1 DHR12R1.
 *
 * 增量式 PID:
 *   u(k) = u(k-1) + Kp*[e(k)-e(k-1)] + Ki*e(k) + Kd*[e(k) - 2e(k-1) + e(k-2)]
 * 其中 e(k) = target - measured.
 *
 * 抗积分饱和: 输出限幅 [0, 3.3V]; 达到限幅时停止累加积分项.
 *
 * 系统特征: DAC->跳线->ADC 直连, 几乎是零惯性一阶系统 (时间常数 << 50ms).
 * 在 50ms 控制周期下, 太大的 Kp 会让 DAC 在两帧之间剧烈抖动, 导致
 * ADC 测得值含 20Hz 谐波, PID 跟着震荡.
 *
 * 保守默认参数 (建议从这开始):
 *   Kp=0.5  -> 比例增益 (小步调节)
 *   Ki=0.2  -> 积分增益 (消除稳态误差)
 *   Kd=0.01 -> 微分增益 (抑制超调)
 *
 * 调参顺序: 先 P (调到不振荡), 再 I (消除稳态误差), 最后 D (抑制超调).
 * 调参命令: 串口 'P:x.x', 'I:x.x', 'D:x.x' 在线修改. */
typedef struct {
    float Kp, Ki, Kd;          /* 比例 / 积分 / 微分系数 */
    float e0, e1, e2;          /* e(k), e(k-1), e(k-2) */
    float output;              /* 当前 DAC 输出电压 [0, 3.3V] */
    uint8_t pid_enabled;       /* 0=开环 (直接写 target), 1=闭环 (PID 调节) */
} pid_state_t;

static pid_state_t pid = {
    .Kp = 0.5f, .Ki = 0.2f, .Kd = 0.01f,
    .e0 = 0, .e1 = 0, .e2 = 0,
    .output = 1.5f,
    .pid_enabled = 1
};

/* 单帧输出增量限幅 (输出变化率限制, 防止 DAC 抖动).
 * 50ms 周期内 DAC 最大允许变化 0.1V = 每秒 2V, 远超 DAC 物理能力. */
#define PID_DU_MAX      0.1f

/* 增量式 PID 计算 — 限幅 + 抗饱和 + 增量限速.
 * 输入 target/measured (V), 返回新的 dac_output (V). */
static float pid_update(float target, float measured)
{
    float e0 = target - measured;
    float delta_u = pid.Kp * (e0 - pid.e1)
                  + pid.Ki * e0
                  + pid.Kd * (e0 - 2.0f * pid.e1 + pid.e2);

    /* 增量限速: 单帧最大变化 PID_DU_MAX (V). 防止 DAC 输出在两帧间跳变 */
    if (delta_u >  PID_DU_MAX) delta_u =  PID_DU_MAX;
    if (delta_u < -PID_DU_MAX) delta_u = -PID_DU_MAX;

    float new_output = pid.output + delta_u;

    /* 输出限幅 */
    if (new_output > 3.3f) new_output = 3.3f;
    if (new_output < 0.0f) new_output = 0.0f;

    /* 抗积分饱和: 仅当未饱和时累加历史误差 */
    if (new_output != 3.3f && new_output != 0.0f) {
        pid.e2 = pid.e1;
        pid.e1 = e0;
    } else {
        /* 饱和时只更新最新一次误差, 不推进 e2 (避免积分 wind-up) */
        pid.e1 = e0;
    }
    pid.output = new_output;
    return new_output;
}

/*---------- Measure 电压曲线图 ----------*
 * "触底式" strip chart: 最新点固定在屏幕最右 (x=PLOT_X1),
 * 旧点随时间向左偏移, 当 plot_count >= PLOT_N 时整条曲线从最右向左滚动.
 *
 * 屏幕图表区: x=[PLOT_X0..PLOT_X1], y=[PLOT_Y0..PLOT_Y1].
 * 纵轴 = 0~3.3V (满量程). */
#define PLOT_N          120   /* 120 点 × 200ms = 24 秒历史 */
#define PLOT_X0         10
#define PLOT_X1         230
#define PLOT_Y0         180   /* 图表区顶 */
#define PLOT_Y1         300   /* 图表区底 */
#define PLOT_W          (PLOT_X1 - PLOT_X0 + 1)
#define PLOT_H          (PLOT_Y1 - PLOT_Y0 + 1)
#define PLOT_VMIN       0.0f
#define PLOT_VMAX       3.3f

/* plot_buf[] 是环形缓冲:
 *   plot_buf[plot_count % PLOT_N] = 最新点 (屏幕最右).
 *   plot_buf[(plot_count - 1) % PLOT_N] = 前一个点 (刚写入的最新).
 *   索引 i = "年龄" = plot_count - 1 - i (i=0 是最新, i=PLOT_N-1 是最老).
 *   屏幕 x 映射: x = PLOT_X1 - i * (PLOT_W-1) / (PLOT_N-1). */
static float plot_buf[PLOT_N];   /* 环形缓冲 */
static uint32_t plot_count = 0;   /* 已采样总数 (持续累加, 用于取模) */

/*---------- 延时 ----------*/
static void delay_ms_local(uint32_t ms) { delay_ms(ms); }

/*---------- GPIO 初始化 ----------*/
static void gpio_init(void)
{
    RCC->AHB1ENR |= RCC_AHB1ENR_GPIOAEN | RCC_AHB1ENR_GPIOCEN | RCC_AHB1ENR_GPIODEN | RCC_AHB1ENR_GPIOEEN | RCC_AHB1ENR_GPIOFEN;

    /* PD12-PD15: output (LEDs, active-low) */
    GPIOD->MODER &= ~(0xFFU << 24);
    GPIOD->MODER |=  (0x55U << 24);
    GPIOD->OTYPER &= ~(0xFU << 12);
    GPIOD->ODR &= ~LED_ALL;   /* active-low: 0=亮 */

    /* PE2, PE3, PE4: input pull-up (KEY0/KEY1/KEY2) */
    GPIOE->MODER &= ~(0x3FU << 4);
    GPIOE->PUPDR &= ~(0x3FU << 4);
    GPIOE->PUPDR |=  (0x15U << 4);

    /* PF8: output, push-pull, no pull-up, default LOW (静音). active-high.
     * 之前因为 PUPDR 未设 (浮空) 导致蜂鸣器一直叫, 现改为下拉. */
    GPIOF->MODER   &= ~(3U << 16);
    GPIOF->MODER   |=  (1U << 16);    /* output */
    GPIOF->OTYPER  &= ~(1U << 8);
    GPIOF->OSPEEDR |=  (3U << 16);
    GPIOF->PUPDR   &= ~(3U << 16);
    GPIOF->PUPDR   |=  (2U << 16);    /* pull-down, 参考 ALIENTEK beep.c */
    GPIOF->ODR     &= ~BUZZER_PIN;    /* PF8=0 默认静音 */
}

/*---------- 按键检测 (非阻塞, 下降沿) ----------*
 * 三个按键均在 GPIOE，按下拉低（上拉有效）。
 * KEY0(PE4) = 电压+0.1V
 * KEY1(PE3) = 电压-0.1V
 * KEY2(PE2) = 报警清除
 * 非阻塞：记录上一次电平，在"高→低"跳变时触发一次，不卡循环。 */
static uint8_t key0_prev = 1, key1_prev = 1, key2_prev = 1;

static uint8_t key0_pressed(void)   /* KEY0 PE4 */
{
    uint8_t cur = (GPIOE->IDR & KEY0_PIN) ? 1 : 0;
    uint8_t edge = (key0_prev == 1 && cur == 0);
    key0_prev = cur;
    return edge;
}

static uint8_t key1_pressed(void)   /* KEY1 PE3 */
{
    uint8_t cur = (GPIOE->IDR & KEY1_PIN) ? 1 : 0;
    uint8_t edge = (key1_prev == 1 && cur == 0);
    key1_prev = cur;
    return edge;
}

static uint8_t key2_pressed(void)   /* KEY2 PE2 */
{
    uint8_t cur = (GPIOE->IDR & KEY2_PIN) ? 1 : 0;
    uint8_t edge = (key2_prev == 1 && cur == 0);
    key2_prev = cur;
    return edge;
}

/*---------- LED/蜂鸣器 (active-low: 高=灭, 低=亮/响) ----------*/
static void led_on(uint32_t led)     { GPIOD->ODR &= ~led; }   /* 低电平点亮 */
static void led_off(uint32_t led)    { GPIOD->ODR |= led; }    /* 高电平熄灭 */
static void led_toggle(uint32_t led) { GPIOD->ODR ^= led; }
/* 蜂鸣器 (PF8): active-high — PF8=1 响, PF8=0 静音 */
static void buzzer_on(void)          { GPIOF->ODR |= BUZZER_PIN; }     /* PF8=1 响 */
static void buzzer_off(void)         { GPIOF->ODR &= ~BUZZER_PIN; }    /* PF8=0 静音 */

/*---------- 浮点转字符串 ----------*/
static void float_to_str(float val, char *buf, int decimals)
{
    int int_part = (int)val;
    float frac = val - (int)val;
    int i = 0;
    if (int_part == 0) {
        buf[i++] = '0';
    } else {
        char tmp[10]; int j = 0, n = int_part;
        while (n > 0) { tmp[j++] = '0' + (n % 10); n /= 10; }
        for (int k = j - 1; k >= 0; k--) buf[i++] = tmp[k];
    }
    buf[i++] = '.';
    for (int d = 0; d < decimals; d++) {
        frac *= 10.0f;
        int digit = (int)frac;
        buf[i++] = '0' + digit;
        frac -= digit;
    }
    buf[i] = '\0';
}

/*---------- 串口状态报告 ----------*/
static void send_status(void)
{
    char buf[32];
    uart_send_string("\r\n========== Status ==========\r\n");

    uart_send_string("Target:   ");
    float_to_str(target_voltage, buf, 2);
    uart_send_string(buf); uart_send_string(" V\r\n");

    uart_send_string("Measured: ");
    float_to_str(measured_voltage, buf, 2);
    uart_send_string(buf); uart_send_string(" V\r\n");

    uart_send_string("Window: [");
    uart_send_number(threshold_low);
    uart_send_string(" - ");
    uart_send_number(threshold_high);
    uart_send_string("]  Volt: [");
    float_to_str((float)threshold_low * 3.3f / 4095.0f, buf, 2);
    uart_send_string(buf); uart_send_string(" ~ ");
    float_to_str((float)threshold_high * 3.3f / 4095.0f, buf, 2);
    uart_send_string(buf); uart_send_string(" V]\r\n");

    uart_send_string("Alarm: ");
    uart_send_string(alarm_active ? "ACTIVE <<<\r\n" : "OFF\r\n");

    uart_send_string("ChipTemp: ");
    float_to_str(chip_temperature, buf, 1);
    uart_send_string(buf); uart_send_string(" C\r\n");

    uart_send_string("PID:     ");
    uart_send_string(pid.pid_enabled ? "ENABLED" : "OFF (open-loop)");
    uart_send_string("  Kp=");
    float_to_str(pid.Kp, buf, 2); uart_send_string(buf);
    uart_send_string(" Ki=");
    float_to_str(pid.Ki, buf, 2); uart_send_string(buf);
    uart_send_string(" Kd=");
    float_to_str(pid.Kd, buf, 3); uart_send_string(buf);
    uart_send_string("\r\nDAC out: ");
    float_to_str(pid.output, buf, 2); uart_send_string(buf);
    uart_send_string(" V\r\n");
    uart_send_string("============================\r\n");
}

/*---------- 串口命令解析 ----------*/
static void parse_command(const char *cmd)
{
    if (cmd[0] == 'V' && cmd[1] == ':') {
        float val = 0.0f;
        const char *p = cmd + 2;
        while (*p >= '0' && *p <= '9') { val = val * 10.0f + (*p - '0'); p++; }
        if (*p == '.') { float f = 0.1f; p++; while (*p >= '0' && *p <= '9') { val += (*p - '0') * f; f *= 0.1f; p++; } }
        if (val > 3.3f) val = 3.3f;
        target_voltage = val;
        if (!pid.pid_enabled) dac_set_voltage(val);
        uart_send_string("OK: V=");
        char buf[16]; float_to_str(val, buf, 2);
        uart_send_string(buf); uart_send_string(" V\r\n");

    } else if ((cmd[0] == 'P' || cmd[0] == 'I' || cmd[0] == 'D') && cmd[1] == ':') {
        /* PID 参数在线整定: P:x.x / I:x.x / D:x.xxx */
        float val = 0.0f;
        const char *p = cmd + 2;
        while (*p >= '0' && *p <= '9') { val = val * 10.0f + (*p - '0'); p++; }
        if (*p == '.') { float f = 0.1f; p++; while (*p >= '0' && *p <= '9') { val += (*p - '0') * f; f *= 0.1f; p++; } }
        if (val < 0) val = -val;     /* 允许负号 */
        if (cmd[0] == 'P') pid.Kp = val;
        else if (cmd[0] == 'I') pid.Ki = val;
        else pid.Kd = val;
        uart_send_string("OK: "); uart_send_char(cmd[0]); uart_send_char('=');
        char buf[16]; float_to_str(val, buf, 3); uart_send_string(buf);
        uart_send_string("\r\n");

    } else if (cmd[0] == 'X' || cmd[0] == 'x') {
        /* X: 切换 PID 开/关 */
        pid.pid_enabled = !pid.pid_enabled;
        uart_send_string("OK: PID ");
        uart_send_string(pid.pid_enabled ? "ENABLED\r\n" : "DISABLED\r\n");
        /* 重置 PID 状态 */
        pid.e0 = pid.e1 = pid.e2 = 0;

    } else if (cmd[0] == 'H' && cmd[1] == ':') {
        uint16_t val = 0;
        const char *p = cmd + 2;
        while (*p >= '0' && *p <= '9') { val = val * 10 + (*p - '0'); p++; }
        if (val > 4095) val = 4095;
        threshold_high = val;
        ADC1->HTR = val;
        uart_send_string("OK: H="); uart_send_number(val); uart_send_string("\r\n");

    } else if (cmd[0] == 'L' && cmd[1] == ':') {
        uint16_t val = 0;
        const char *p = cmd + 2;
        while (*p >= '0' && *p <= '9') { val = val * 10 + (*p - '0'); p++; }
        if (val > 4095) val = 4095;
        threshold_low = val;
        ADC1->LTR = val;
        uart_send_string("OK: L="); uart_send_number(val); uart_send_string("\r\n");

    } else if (cmd[0] == '?') {
        send_status();

    } else if (cmd[0] == 'R' || cmd[0] == 'r') {
        alarm_active = 0;
        adc_watchdog_clear();
        buzzer_off();
        uart_send_string("OK: Alarm cleared\r\n");

    } else {
        uart_send_string("Commands: V:x.xx H:nnnn L:nnnn ? R P:xx.xx I:xx.xx D:xx.xxx X\r\n");
    }
}

/*---------- 串口接收缓冲区 ----------*/
static char rx_buf[32];
static uint8_t rx_idx = 0;

/*---------- LCD 显示 ----------*/
/* 把电压值映射到图表 y 坐标 (PLOT_Y0=上, PLOT_Y1=下, 满量程 PLOT_VMIN..VMAX) */
static inline uint16_t plot_v_to_y(float v)
{
    if (v < PLOT_VMIN) v = PLOT_VMIN;
    if (v > PLOT_VMAX) v = PLOT_VMAX;
    /* 反转: v=VMAX -> y=PLOT_Y0 (上), v=VMIN -> y=PLOT_Y1 (下) */
    float frac = (v - PLOT_VMIN) / (PLOT_VMAX - PLOT_VMIN);
    return PLOT_Y1 - (uint16_t)(frac * (float)(PLOT_H - 1));
}

/* 把"年龄"映射到 x 坐标 (触底式: age=0=最新, x=PLOT_X1; age=PLOT_N-1=最老, x=PLOT_X0) */
static inline uint16_t plot_age_to_x(uint16_t age)
{
    return PLOT_X1 - (uint32_t)age * (PLOT_W - 1) / (PLOT_N - 1);
}

/* Draw the static labels once at startup (title + field names + chart frame). */
static void lcd_draw_layout(void)
{
    POINT_COLOR = BLACK;
    BACK_COLOR  = WHITE;
    LCD_Clear(WHITE);

    /* Title bar */
    POINT_COLOR = WHITE;
    LCD_Fill(0, 0, lcddev.width - 1, 24, BLUE);
    LCD_ShowString(8, 4, lcddev.width - 8, 24, 16, (u8 *)"Closed-Loop Control System");

    POINT_COLOR = BLACK;
    LCD_ShowString(10, 32,  200, 16, 16, (u8 *)"Target  V:");
    LCD_ShowString(10, 52,  200, 16, 16, (u8 *)"Measure V:");
    LCD_ShowString(10, 72,  200, 16, 16, (u8 *)"Window   :");
    LCD_ShowString(10, 92,  200, 16, 16, (u8 *)"Chip Temp:");
    LCD_ShowString(10, 112, 200, 16, 16, (u8 *)"Alarm    :");
    LCD_ShowString(10, 132, 200, 16, 12, (u8 *)"PID:");

    /* ===== 图表区静态部分: 标题 + 边框 + Y 轴标签 ===== *
     * 网格线和阈值线随曲线在 lcd_update_values 中每次重绘 (因为屏幕会清空). */
    POINT_COLOR = DARKBLUE;
    LCD_ShowString(10, 152, 200, 16, 12, (u8 *)"Measure V History:");
    POINT_COLOR = BLACK;

    /* Outer frame */
    LCD_DrawRectangle(PLOT_X0 - 1, PLOT_Y0 - 1, PLOT_X1 + 1, PLOT_Y1 + 1);

    /* Y-axis labels (right of frame) */
    POINT_COLOR = BLACK;
    LCD_ShowChar(PLOT_X1 + 4, PLOT_Y0 - 6,     '3', 12, 0);
    LCD_ShowString(PLOT_X1 + 12, PLOT_Y0 - 6,  20, 12, 12, (u8 *)".3V");
    LCD_ShowString(PLOT_X1 + 4, PLOT_Y1 - 8,   20, 12, 12, (u8 *)"0V");
    LCD_ShowString(PLOT_X1 + 4, (PLOT_Y0 + PLOT_Y1) / 2 - 6, 20, 12, 12, (u8 *)"1.6V");
}

/* Show a float value as "d.dd" starting at (x,y). idigits = integer digits. */
static void lcd_show_float(u16 x, u16 y, float val, u8 size, u8 idigits)
{
    if (val < 0) val = 0;
    uint16_t whole = (uint16_t)val;
    uint16_t frac  = (uint16_t)((val - whole) * 100.0f + 0.5f);
    if (frac >= 100) { whole += 1; frac -= 100; }
    u16 hw = size / 2;               /* character cell width */
    LCD_ShowNum(x, y, whole, idigits, size);
    x += idigits * hw;
    LCD_ShowChar(x, y, '.', size, 0);           x += hw;
    LCD_ShowNum(x, y, frac / 10, 1, size);      x += hw;
    LCD_ShowNum(x, y, frac % 10, 1, size);
}

/* Refresh the dynamic values on the LCD. */
static void lcd_update_values(void)
{
    const u16 vx = 100;   /* value column */

    POINT_COLOR = BLUE;
    lcd_show_float(vx, 32, target_voltage, 16, 1);
    LCD_ShowString(vx + 60, 32, 40, 16, 16, (u8 *)"V");

    POINT_COLOR = alarm_active ? RED : GREEN;
    lcd_show_float(vx, 52, measured_voltage, 16, 1);
    LCD_ShowString(vx + 60, 52, 40, 16, 16, (u8 *)"V");

    /* Window thresholds (12-bit raw) */
    POINT_COLOR = BLACK;
    LCD_ShowNum(vx, 72, threshold_low, 4, 16);
    LCD_ShowChar(vx + 40, 72, '-', 16, 0);
    LCD_ShowNum(vx + 56, 72, threshold_high, 4, 16);

    /* Chip temperature (2 integer digits) */
    POINT_COLOR = MAGENTA;
    lcd_show_float(vx, 92, chip_temperature, 16, 2);
    LCD_ShowString(vx + 4 * 8, 92, 40, 16, 16, (u8 *)"C");

    /* Alarm state */
    if (alarm_active) {
        POINT_COLOR = RED;
        LCD_ShowString(vx, 112, 120, 16, 16, (u8 *)"ALARM! ");
    } else {
        POINT_COLOR = GREEN;
        LCD_ShowString(vx, 112, 120, 16, 16, (u8 *)"NORMAL ");
    }

    /* PID 参数行 (12 号字) */
    {
        POINT_COLOR = pid.pid_enabled ? DARKBLUE : GRAY;
        char pid_buf[40];
        /* 格式: "ON  Kp=2.00 Ki=1.50"  (留 Kd 下一行? 屏幕太窄, 一行放 Kp/Ki) */
        int i = 0;
        pid_buf[i++] = pid.pid_enabled ? 'O' : 'o';
        pid_buf[i++] = pid.pid_enabled ? 'n' : 'f';
        pid_buf[i++] = ' ';
        pid_buf[i++] = 'P'; pid_buf[i++] = '=';
        float_to_str(pid.Kp, pid_buf + i, 2); i += 4;
        pid_buf[i++] = ' ';
        pid_buf[i++] = 'I'; pid_buf[i++] = '=';
        float_to_str(pid.Ki, pid_buf + i, 2); i += 4;
        pid_buf[i] = '\0';
        LCD_ShowString(50, 132, 200, 16, 12, (u8 *)pid_buf);
    }

    /* ===== 图表重绘 (触底式 strip chart) =====
     * 最新点固定在屏幕最右, 旧点向左偏移. 每次整屏清空 + 重画全部已有数据.
     * PLOT_N=120 点 × LCD_DrawLine (Bresenham ~ 单点 200ns) ≈ 24ms,
     * 在 200ms 刷新周期内完全可以接受, 且避免了增量绘制的复杂度. */
    {
        /* 写入新值到环形缓冲的最新位置 */
        plot_buf[plot_count % PLOT_N] = measured_voltage;
        plot_count++;

        /* 清空图表区 (不包括边框, 边框画在 lcd_draw_layout 静态部分) */
        POINT_COLOR = WHITE;
        LCD_Fill(PLOT_X0, PLOT_Y0, PLOT_X1, PLOT_Y1, WHITE);

        /* 重新画网格 + 阈值线 (静态, 每次重绘都要画) */
        POINT_COLOR = GRAY;
        for (uint8_t i = 1; i <= 3; i++) {
            uint16_t y = PLOT_Y0 + i * PLOT_H / 4;
            LCD_DrawLine(PLOT_X0, y, PLOT_X1, y);
        }
        POINT_COLOR = MAGENTA;
        {
            uint16_t yh = plot_v_to_y((float)threshold_high * 3.3f / 4095.0f);
            uint16_t yl = plot_v_to_y((float)threshold_low  * 3.3f / 4095.0f);
            for (uint16_t x = PLOT_X0; x <= PLOT_X1; x += 8) {
                uint16_t xe = (x + 4 <= PLOT_X1) ? (x + 4) : PLOT_X1;
                LCD_DrawLine(x, yh, xe, yh);
                LCD_DrawLine(x, yl, xe, yl);
            }
        }

        /* 画曲线.
         * age=0 = 最新点 (屏幕最右); age=PLOT_N-1 = 最老点 (屏幕最左).
         * plot_count < PLOT_N 时, 只有前 plot_count 个点是有效历史, 后面为空. */
        POINT_COLOR = alarm_active ? RED : BLUE;
        uint32_t n_valid = (plot_count < PLOT_N) ? plot_count : PLOT_N;
        if (n_valid >= 2) {
            uint16_t prev_x = plot_age_to_x(0);
            uint16_t prev_y = plot_v_to_y(plot_buf[(plot_count - 1) % PLOT_N]);
            for (uint32_t age = 1; age < n_valid; age++) {
                uint32_t idx = (plot_count - 1 - age) % PLOT_N;
                uint16_t x = plot_age_to_x((uint16_t)age);
                uint16_t y = plot_v_to_y(plot_buf[idx]);
                LCD_DrawLine(prev_x, prev_y, x, y);
                prev_x = x;
                prev_y = y;
            }
        }
    }

    POINT_COLOR = BLACK;
}


int main(void)
{
    system_init();
    gpio_init();
    uart_init(115200);
    dac_init();
    adc_init();
    LCD_Init();

    /* LED heartbeat: blink to confirm code is running */
    led_on(LED_BLUE);

    lcd_draw_layout();

    uart_send_string("\r\n=== Closed-Loop PID Control ===\r\n");
    uart_send_string("DAC(PA4)->ADC(PA5) Incremental PID\r\n");
    uart_send_string("Keys: KEY2=UP(+0.1V) KEY0=DOWN KEY1=TogglePID/Clr\r\n");
    uart_send_string("UART: V:x.xx H:nnnn L:nnnn ? R P:xx.xx I:xx.xx D:xx.xxx X\r\n\r\n");

    dac_set_voltage(target_voltage);
    pid.output = target_voltage;          /* PID 初始输出 = 目标 */
    ADC1->HTR = threshold_high;
    ADC1->LTR = threshold_low;
    adc_watchdog_enable(1);

    while (1) {
        uint32_t now = get_tick();

        /*--- LED heartbeat (500ms) ---*/
        static uint32_t last_hb_tick = 0;
        if ((now - last_hb_tick) >= 500) {
            last_hb_tick = now;
            led_toggle(LED_BLUE);
        }

        /*--- 按键扫描 (200ms) ---*
         * KEY2 (PE2) = 左键 → 目标电压 +0.1V
         * KEY0 (PE4) = 右键 → 目标电压 -0.1V
         * KEY1 (PE3) = 下键 → 报警清除 / PID 开关
         *
         * PID 启用时: 按键只改 target, 不直接动 DAC.
         * DAC 输出由 ADC 采样后由 pid_update() 计算. */
        static uint32_t last_key_tick = 0;
        if ((now - last_key_tick) >= 200) {
            last_key_tick = now;
            if (key2_pressed()) {        /* PE2 左键: 目标+0.1V */
                target_voltage += 0.1f;
                if (target_voltage > 3.3f) target_voltage = 3.3f;
                if (!pid.pid_enabled) dac_set_voltage(target_voltage);
                uart_send_string("KEY2+: target=");
                char buf[16]; float_to_str(target_voltage, buf, 2);
                uart_send_string(buf); uart_send_string(" V\r\n");
            }
            if (key0_pressed()) {        /* PE4 右键: 目标-0.1V */
                target_voltage -= 0.1f;
                if (target_voltage < 0.0f) target_voltage = 0.0f;
                if (!pid.pid_enabled) dac_set_voltage(target_voltage);
                uart_send_string("KEY0-: target=");
                char buf[16]; float_to_str(target_voltage, buf, 2);
                uart_send_string(buf); uart_send_string(" V\r\n");
            }
            if (key1_pressed()) {        /* PE3 下键: 清报警 + 切换 PID */
                alarm_active = 0;
                adc_watchdog_clear();
                pid.pid_enabled = !pid.pid_enabled;
                uart_send_string("KEY1: PID ");
                uart_send_string(pid.pid_enabled ? "ENABLED\r\n" : "DISABLED (open-loop)\r\n");
            }
        }

        /*--- ADC采集 + PID控制 + 窗口检测 (50ms = 20Hz 控制周期) ---*/
        static uint32_t last_adc_tick = 0;
        if ((now - last_adc_tick) >= 50) {
            last_adc_tick = now;
            uint16_t adc_raw = adc_read();
            measured_voltage = (float)adc_raw * 3.3f / 4095.0f;

            /* PID 计算 -> DAC 输出 */
            if (pid.pid_enabled) {
                float dac_v = pid_update(target_voltage, measured_voltage);
                dac_set_voltage(dac_v);
            } else {
                /* 开环模式: DAC 直接跟随 target */
                pid.output = target_voltage;
                dac_set_voltage(target_voltage);
            }

            /* 窗口检测 */
            if (adc_raw > threshold_high || adc_raw < threshold_low) {
                alarm_active = 1;
            } else {
                alarm_active = 0;
            }
        }

        /*--- 报警: LED闪烁 + 蜂鸣器鸣叫 (250ms 周期) ---*
         * PD14/PD15 被 LCD FSMC 数据线占用, 报警闪烁用 PD12(Green) + PD13(Orange).
         * 蜂鸣器 (PF8, active-high) 同步鸣叫, 形成间断报警 (哔-哔-哔).
         * 正常状态: PD12 常亮, PD13 常灭, 蜂鸣器静音. */
        static uint32_t last_blink_tick = 0;
        if (alarm_active) {
            if ((now - last_blink_tick) >= 250) {
                last_blink_tick = now;
                blink_state ^= 1;
                if (blink_state) {
                    led_off(LED_GREEN);
                    led_on(LED_ORANGE);
                    buzzer_on();         /* 前半周期: 鸣叫 */
                } else {
                    led_on(LED_GREEN);
                    led_off(LED_ORANGE);
                    buzzer_off();        /* 后半周期: 静音 */
                }
            }
        } else {
            led_on(LED_GREEN);
            led_off(LED_ORANGE);
            buzzer_off();                /* 正常状态强制静音 */
        }

        /*--- 芯片温度采集 (500ms) ---*/
        static uint32_t last_temp_tick = 0;
        if ((now - last_temp_tick) >= 500) {
            last_temp_tick = now;
            chip_temperature = adc_read_temperature();
            /* One-shot VREFINT probe (ADC1_IN17, ~1.21V bandgap). With Vdda=3.3V,
             * expected raw ≈ 1.21/3.3 * 4095 ≈ 1502. Read via SWD. */
            static uint8_t vref_probed = 0;
            if (!vref_probed) {
                vrefint_raw = (float)adc_read_vrefint_raw();
                vref_probed = 1;
            }
        }

        /*--- LCD 刷新 (200ms) ---*/
        static uint32_t last_lcd_tick = 0;
        if ((now - last_lcd_tick) >= 200) {
            last_lcd_tick = now;
            lcd_update_values();
        }

        /*--- 串口自动上报 (2s) ---*/
        static uint32_t last_report_tick = 0;
        if ((now - last_report_tick) >= 2000) {
            last_report_tick = now;
            send_status();
        }

        /*--- 串口接收 ---*/
        int c = uart_receive_char();
        if (c >= 0) {
            if (c == '\r' || c == '\n') {
                if (rx_idx > 0) { rx_buf[rx_idx] = '\0'; parse_command(rx_buf); rx_idx = 0; }
            } else {
                if (rx_idx < sizeof(rx_buf) - 1) rx_buf[rx_idx++] = (char)c;
            }
        }
    }
}
